import {
  CalendarOutlined,
  CreditCardOutlined,
  EnvironmentOutlined,
  HomeOutlined,
  MailOutlined,
  PhoneOutlined,
  UserOutlined,
} from "@ant-design/icons"
import {
  Button,
  Checkbox,
  Col,
  DatePicker,
  Divider,
  Form,
  Input,
  message,
  Row,
  Select,
  Typography,
} from "antd"
import dayjs from "dayjs"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import notice from "src/components/Notice"
import { GUIDE_ONE } from "src/constants/constants"
import { getRegexMobile } from "src/lib/stringsUtils"
import AuthService from "src/services/AuthService"
import MediaUploadPreview from "./MediaUploadPreview"
import UserService from "src/services/UserService"
import AdvertisementService from "src/services/Advertisement"
import DrawerViewPDF from "src/components/DrawerViewPDF"
import ButtonCustom from "src/components/MyButton/Button"

const { Title } = Typography
const { RangePicker } = DatePicker

const AssociationForm = ({
  treeData,
  setTreeData,
  loading = false,
  setLoading = () => {},
  onSuccess = () => {},
}) => {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [form] = Form.useForm()

  // State for media preview
  const [previewBanner, setPreviewBanner] = useState(null)
  const [isUploadingBanner, setIsUploadingBanner] = useState(false)
  const [isSubmitting, setIsSubmitting] = useState(false)
  // const [isCheckingConflict, setIsCheckingConflict] = useState(false)

  //- pdf
  const [showPdfModal, setShowPdfModal] = useState(false)
  const [pdfFileUrl, setPdfFileUrl] = useState("")
  const [pdfFileName, setPdfFileName] = useState("")
  const [pdfLoading, setPdfLoading] = useState(false)
  const [confirmedRead, setConfirmedRead] = useState(false)

  //- payment
  const [qrPayment, setQrPayment] = useState("")
  const [modalQr, setModalQr] = useState(false)

  const [payMentSuccess, setPayMentSuccess] = useState(false)
  const [modalPayMentSuccess, setModalPayMentSuccess] = useState(false)

  // Advertisement position options with search support

  const [advertisementPositions, setAdvertisementPositions] = useState([])

  const handleCreateAssoc = async () => {
    try {
      setLoading(true)
      setIsSubmitting(true)

      const values = await form.validateFields()

      let formattedValues = { ...values }

      // Format date
      if (values.advertisementDateRange) {
        formattedValues.StartDate = values.advertisementDateRange[0].format(
          "YYYY-MM-DDTHH:mm:ss[Z]",
        )
        formattedValues.EndDate = values.advertisementDateRange[1].format(
          "YYYY-MM-DDTHH:mm:ss[Z]",
        )
        delete formattedValues.advertisementDateRange
      }

      // Rename cho đúng với Swagger
      formattedValues.RepresentativeName = values.Name
      formattedValues.RepresentativePosition = values.Position
      delete formattedValues.Name
      delete formattedValues.Position

      formattedValues.Status = 2

      // Tạo FormData
      const formData = new FormData()
      Object.keys(formattedValues).forEach(key => {
        const value = formattedValues[key]

        if (Array.isArray(value)) {
          value.forEach(v => formData.append(key, v))
        } else {
          formData.append(key, value)
        }
      })

      // Call API
      const res = await AdvertisementService.makeAdvertisingContract(formData)

      if (res?.isError) {
        console.error("API error:", res?.Object, res?.status)
        notice({
          isSuccess: false,
          msg: res?.Object || "Có lỗi khi gửi yêu cầu",
        })
        return
      }

      const getLinkPdf = await AdvertisementService.getAdvertisingContractForm(
        res.Object,
      )

      if (getLinkPdf?.isError) {
        console.error("API error:", getLinkPdf?.Object, getLinkPdf?.status)
        notice({
          isSuccess: false,
          msg: getLinkPdf?.Object || "Có lỗi khi gửi yêu cầu",
        })
        return
      }

      setPdfFileUrl(getLinkPdf?.Object)
      setPdfFileName("ĐƠN XIN ĐĂNG KÝ QUẢNG CÁO")
      setShowPdfModal(true)

      form.resetFields()
      setPreviewBanner(null)
    } catch (err) {
      console.error("Error:", err)
      notice({
        isSuccess: false,
        msg: "Có lỗi xảy ra",
      })
    } finally {
      setLoading(false)
      setIsSubmitting(false)
    }
  }

  const searchInfoByCode = async code => {
    if (!code) return
    try {
      setLoading(true)
      const res1 = await AuthService.getInfoByTaxCode(code)
      if (res1.data.code === "00") {
        form.setFieldsValue({
          OrganizationName: res1.data?.data?.name,
          Address: res1.data?.data?.address,
        })
      } else {
        notice({
          isSuccess: false,
          msg: res1.data.desc,
        })
      }
    } finally {
      setLoading(false)
    }
  }

  const handleReferrerChange = e => {
    const value = e.target.value
    if (value && value.trim()) {
      searchInfoByCode(value.trim())
    }
  }

  const handleBannerFileChange = file => {
    if (file) {
      setIsUploadingBanner(true)
      setTimeout(() => {
        setIsUploadingBanner(false)
      }, 1000)
    } else {
      setIsUploadingBanner(false)
    }
  }

  const validateDateRange = (_, value) => {
    if (!value || !value[0] || !value[1]) {
      return Promise.reject(
        new Error("Vui lòng chọn ngày bắt đầu và ngày kết thúc"),
      )
    }

    const [startDate, endDate] = value
    const today = dayjs().startOf("day")

    if (startDate.isBefore(today)) {
      return Promise.reject(new Error("Ngày bắt đầu phải từ hôm nay trở đi"))
    }

    if (!endDate.isAfter(startDate)) {
      return Promise.reject(new Error("Ngày kết thúc phải sau ngày bắt đầu"))
    }

    const daysDiff = endDate.diff(startDate, "days")
    if (daysDiff < 30) {
      return Promise.reject(
        new Error("Thời gian quảng cáo tối thiểu là 30 ngày"),
      )
    }

    const monthsDiff = endDate.diff(startDate, "months", true)
    if (monthsDiff > 13) {
      return Promise.reject(
        new Error("Thời gian quảng cáo không được vượt quá 13 tháng"),
      )
    }

    return Promise.resolve()
  }

  const handlePdfModalConfirm = () => {
    if (!confirmedRead) {
      message.warning("Vui lòng xác nhận đã đọc điều khoản và điều kiện!")
      return
    }

    if (pdfLoading) {
      message.warning("Vui lòng chờ file PDF tải xong!")
      return
    }
    setShowPdfModal(false)
    setModalQr(true)
  }

  useEffect(() => {
    const fetchDataUser = async () => {
      try {
        const res = await UserService.getInforUser()
        if (res?.isError) return

        //- set default value for form
        form.setFieldsValue({
          Name: res.Object.BasicInfo.FullName,
          Position: res.Object.BasicInfo.Occupation,
          PhoneNumber: res.Object.BasicInfo.PhoneNumber,
        })
      } catch (error) {
        console.error("Lỗi khi tải thông tin:", error)
      } finally {
        // console.error("Lỗi khi tải thông tin:")
      }
    }

    const fetchDataAdvertisementPosition = async () => {
      const res = await AdvertisementService.getListAdvertisingPosition()
      if (res?.isError) setAdvertisementPositions([])
      setAdvertisementPositions(res.Object)
    }
    fetchDataUser()
    fetchDataAdvertisementPosition()
  }, [])

  return (
    <div style={{ padding: "20px", minHeight: "500px" }}>
      <Form
        form={form}
        layout="vertical"
        size="middle"
        initialValues={{
          SortOrder: 0,
          Status: 2,
          AssociationType: 1,
          ParentId: GUIDE_ONE,
          EstablishmentDate: dayjs(),
        }}
        onFinish={handleCreateAssoc}
      >
        <Row gutter={[20, 12]}>
          <Col xs={24} lg={24}>
            <Row gutter={[16, 12]}>
              <Col xs={24} sm={8}>
                <Form.Item
                  label={
                    <span style={{ fontWeight: 600, fontSize: 14 }}>
                      <UserOutlined
                        style={{ marginRight: 6, color: "#01b39e" }}
                      />
                      Đại diện
                    </span>
                  }
                  name="Name"
                  rules={[
                    {
                      required: true,
                      message: "Vui lòng nhập tên người đại diện",
                    },
                  ]}
                  style={{ marginBottom: 16 }}
                >
                  <Input
                    placeholder="Nhập tên người đại diện"
                    style={{ borderRadius: 6 }}
                    prefix={<UserOutlined style={{ color: "#bfbfbf" }} />}
                  />
                </Form.Item>
              </Col>
              <Col xs={24} sm={8}>
                <Form.Item
                  label={
                    <span style={{ fontWeight: 600, fontSize: 14 }}>
                      <MailOutlined
                        style={{ marginRight: 6, color: "#01b39e" }}
                      />
                      Chức Vụ
                    </span>
                  }
                  name="Position"
                  rules={[
                    {
                      required: true,
                      message: "Vui lòng nhập chức vụ",
                    },
                  ]}
                  style={{ marginBottom: 16 }}
                >
                  <Input
                    placeholder="Nhập chức vụ"
                    style={{ borderRadius: 6 }}
                    prefix={<MailOutlined style={{ color: "#bfbfbf" }} />}
                  />
                </Form.Item>
              </Col>
              <Col xs={24} sm={8}>
                <Form.Item
                  label={
                    <span style={{ fontWeight: 600, fontSize: 14 }}>
                      <PhoneOutlined
                        style={{ marginRight: 6, color: "#01b39e" }}
                      />
                      Số điện thoại
                    </span>
                  }
                  name="PhoneNumber"
                  rules={[
                    {
                      required: true,
                      pattern: getRegexMobile(),
                      message: "Số điện thoại từ 10-11 chữ số",
                    },
                  ]}
                  style={{ marginBottom: 16 }}
                >
                  <Input
                    placeholder="Nhập số điện thoại"
                    style={{ borderRadius: 6 }}
                    prefix={<PhoneOutlined style={{ color: "#bfbfbf" }} />}
                  />
                </Form.Item>
              </Col>
            </Row>
          </Col>
          <Col xs={24} lg={24}>
            <Row gutter={[16, 12]}>
              <Col xs={24} sm={8}>
                <Form.Item
                  label={
                    <span style={{ fontWeight: 600, fontSize: 14 }}>
                      <CalendarOutlined
                        style={{ marginRight: 6, color: "#01b39e" }}
                      />
                      Tài khoản số
                    </span>
                  }
                  name="AccountNumber"
                  rules={[
                    { required: true, message: "Vui lòng nhập tài khoản số" },
                  ]}
                  style={{ marginBottom: 16 }}
                >
                  <Input
                    placeholder="Nhập tài khoản số"
                    style={{ borderRadius: 6 }}
                    prefix={<CalendarOutlined style={{ color: "#bfbfbf" }} />}
                  />
                </Form.Item>
              </Col>

              <Col xs={24} sm={8}>
                <Form.Item
                  label={
                    <span style={{ fontWeight: 600, fontSize: 14 }}>
                      <HomeOutlined
                        style={{ marginRight: 6, color: "#01b39e" }}
                      />
                      Mã số thuế
                    </span>
                  }
                  name="TaxCode"
                  rules={[
                    { required: true, message: "Vui lòng nhập mã số thuế" },
                  ]}
                  style={{ marginBottom: 20 }}
                >
                  <Input
                    placeholder="Nhập mã số thuế"
                    onBlur={handleReferrerChange}
                  />
                </Form.Item>
              </Col>

              <Col xs={24} sm={8}>
                <Form.Item
                  re
                  label={
                    <span style={{ fontWeight: 600, fontSize: 14 }}>
                      <MailOutlined
                        style={{ marginRight: 6, color: "#01b39e" }}
                      />
                      Địa chỉ
                    </span>
                  }
                  name="Address"
                  rules={[
                    {
                      required: true,
                      message: "Vui lòng nhập địa chỉ",
                    },
                  ]}
                  style={{ marginBottom: 16 }}
                >
                  <Input
                    readOnly
                    placeholder="Hệ thống sẽ tự động điền khi bạn nhập mã số thuế"
                    style={{ borderRadius: 6 }}
                    prefix={<MailOutlined style={{ color: "#bfbfbf" }} />}
                  />
                </Form.Item>
              </Col>
            </Row>
          </Col>

          <Divider />

          <Col xs={24} lg={24}>
            <Form.Item
              label={
                <span style={{ fontWeight: 600, fontSize: 14 }}>
                  <HomeOutlined style={{ marginRight: 6, color: "#01b39e" }} />
                  Nội dung quảng cáo
                </span>
              }
              name="AdvertisementContent"
              rules={[
                { required: true, message: "Vui lòng nhập nội dung quảng cáo" },
              ]}
              style={{ marginBottom: 20 }}
            >
              <Input.TextArea
                rows={4}
                style={{ borderRadius: 6 }}
                placeholder="Nhập nội dung quảng cáo"
              />
            </Form.Item>
          </Col>

          <Col xs={24} lg={24}>
            <Form.Item
              name="Files"
              rules={[
                {
                  required: true,
                  message: "Vui lòng upload banner/logo/video",
                },
              ]}
            >
              <MediaUploadPreview
                previewMedia={previewBanner}
                setPreviewMedia={setPreviewBanner}
                fieldName="Files"
                form={form}
                label="Banner/Logo/Video"
                onFileChange={handleBannerFileChange}
                disabled={isSubmitting || isUploadingBanner}
                loading={isUploadingBanner}
              />
            </Form.Item>
          </Col>
          <Col xs={24} lg={12}>
            <Form.Item
              label={
                <span style={{ fontWeight: 600, fontSize: 14 }}>
                  <CalendarOutlined
                    style={{ marginRight: 6, color: "#01b39e" }}
                  />
                  Thời gian quảng cáo
                </span>
              }
              name="advertisementDateRange"
              rules={[{ validator: validateDateRange }]}
              style={{ marginBottom: 20 }}
            >
              <RangePicker
                style={{ width: "100%", borderRadius: 6 }}
                placeholder={["Ngày bắt đầu", "Ngày kết thúc"]}
                format="DD/MM/YYYY"
                disabledDate={current => {
                  return current && current < dayjs().startOf("day")
                }}
              />
            </Form.Item>
          </Col>

          <Col xs={24} lg={12}>
            <Form.Item
              label={
                <span style={{ fontWeight: 600, fontSize: 14 }}>
                  <EnvironmentOutlined
                    style={{ marginRight: 6, color: "#01b39e" }}
                  />
                  Vị trí quảng cáo
                </span>
              }
              name="AdPositionIds"
              rules={[
                {
                  required: true,
                  message: "Vui lòng chọn ít nhất một vị trí quảng cáo",
                },
              ]}
              style={{ marginBottom: 20 }}
            >
              <Select
                mode="multiple"
                placeholder="Chọn vị trí quảng cáo (có thể chọn nhiều)"
                style={{ borderRadius: 6 }}
                showSearch
                filterOption={(input, option) => {
                  const searchText = input.toLowerCase()
                  return (
                    option.children.toLowerCase().includes(searchText) || // match theo tên
                    option["data-description"]
                      ?.toLowerCase()
                      .includes(searchText) // match theo mô tả
                  )
                }}
                maxTagCount="responsive"
              >
                {advertisementPositions?.map(position => (
                  <Select.Option
                    key={position.AdPositionId}
                    value={position.AdPositionId}
                    data-description={position.Description} // thêm description để search
                  >
                    {position.Position}
                  </Select.Option>
                ))}
              </Select>
            </Form.Item>
          </Col>

          <Col xs={24} md={12}>
            <Form.Item
              label={
                <span style={{ fontWeight: 600, fontSize: 14 }}>
                  <HomeOutlined style={{ marginRight: 6, color: "#01b39e" }} />
                  Mã người giới thiệu (nếu có)
                </span>
              }
              name="ReferrerCode"
              style={{ marginBottom: 20 }}
            >
              <Input placeholder="Nhập mã người giới thiệu" />
            </Form.Item>
          </Col>

          <Form.Item label={null} style={{ textAlign: "right" }}>
            <Button type="primary" htmlType="submit" loading={isSubmitting}>
              Đăng ký
            </Button>
          </Form.Item>
        </Row>
      </Form>

      <DrawerViewPDF
        open={showPdfModal}
        onClose={() => setShowPdfModal(false)}
        fileUrl={pdfFileUrl}
        attachmentName={pdfFileName}
        title="ĐƠN XIN ĐĂNG KÝ QUẢNG CÁO.pdf"
        loading={pdfLoading}
        placement="right"
        width={1024}
        titleDrawer
        subFooter={() => (
          <>
            <Checkbox
              checked={confirmedRead}
              onChange={e => setConfirmedRead(e.target.checked)}
              style={{ marginRight: "auto", alignItems: "center" }}
              disabled={pdfLoading}
            >
              Tôi đã đọc và xác nhận thông tin trong đơn là chính xác
            </Checkbox>
            <ButtonCustom
              type="primary"
              onClick={handlePdfModalConfirm}
              disabled={!confirmedRead || pdfLoading}
              icon={<CreditCardOutlined />}
              style={{ marginRight: "8px" }}
              loading={pdfLoading}
            >
              {pdfLoading ? "Đang tải..." : "Tiếp tục thanh toán"}
            </ButtonCustom>
          </>
        )}
      />
    </div>
  )
}

export default AssociationForm
